// ── Folder card ─────────────────────────────────────────────────────────────

interface FolderCardProps {
  section: VfsSection
  isSelected: boolean
  onToggle: (path: string) => void
}

function FolderCard({ section, isSelected, onToggle }: FolderCardProps) {
  const visibleTypes = section.types.slice(0, 4)
  const overflow = section.types.length > 4 ? section.types.length - 4 : 0
  const count = section.items.length

  return (
    <button
