        <div className="absolute left-2 top-0 h-3 w-[38%] rounded-t-md bg-violet-400/40" />
        {/* Depth / shadow layer */}
        <div className="absolute inset-x-1 bottom-0 top-3 translate-y-1 scale-[0.97] rounded-xl bg-violet-400/25 blur-[3px]" />
        {/* Main body */}
        <div className="absolute inset-x-0 bottom-0 top-3 overflow-hidden rounded-xl bg-gradient-to-br from-violet-400 to-violet-600">
